import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import kotlin.math.abs

/**
 * iOS-style wheel picker.
 * Renders 5 visible rows; selected row is the middle one.
 * Range is 0..maxValue inclusive.
 */
@Composable
fun WheelPicker(
    label: String,
    value: Int,
    maxValue: Int,
    onValueChange: (Int) -> Unit,
    modifier: Modifier = Modifier,
) {
    val itemHeight = 56.dp
    val visibleCount = 5
    val paddingItems = (visibleCount - 1) / 2

    val state = rememberLazyListState(initialFirstVisibleItemIndex = value)
    val fling = rememberSnapFlingBehavior(lazyListState = state)

    LaunchedEffect(state) {
        snapshotFlow {
            // Item whose start is closest to the viewport center == the centered item.
            val info = state.layoutInfo
            val center = info.viewportStartOffset + info.viewportSize.height / 2
            info.visibleItemsInfo.minByOrNull {
                abs((it.offset + it.size / 2) - center)
            }?.index ?: 0
        }.collect { idx ->
            val clamped = idx.coerceIn(0, maxValue)
            if (clamped != value) onValueChange(clamped)
        }
    }

    LaunchedEffect(value) {
        // Keep external value in sync (e.g. when reset).
        val info = state.layoutInfo
        val center = info.viewportStartOffset + info.viewportSize.height / 2
        val currentCentered = info.visibleItemsInfo.minByOrNull {
            abs((it.offset + it.size / 2) - center)
        }?.index
        if (currentCentered != value) {
            state.animateScrollToItem(value)
        }
    }

    Box(
        modifier = modifier
            .width(96.dp)
            .height(itemHeight * visibleCount),
        contentAlignment = Alignment.Center,
    ) {
        // Highlight bar for the center row.
        Box(
            Modifier
                .fillMaxWidth()
                .height(itemHeight)
                .background(
                    color = Color.White.copy(alpha = 0.06f),
                    shape = RoundedCornerShape(12.dp),
                )
        )

        LazyColumn(
            state = state,
            flingBehavior = fling,
            modifier = Modifier.fillMaxWidth(),
        ) {
            items(paddingItems) {
                Spacer(Modifier.height(itemHeight))
            }
            items(maxValue + 1) { idx ->
                WheelItem(
                    text = "%02d".format(idx),
                    itemHeight = itemHeight,
                    isSelected = idx == value,
                    distanceFromSelected = abs(idx - value),
                )
            }
            items(paddingItems) {
                Spacer(Modifier.height(itemHeight))
            }
        }

        // Label in lowercase next to the centered number
        Text(
            text = label,
            color = MaterialTheme.colorScheme.onBackground.copy(alpha = 0.7f),
            fontSize = 16.sp,
            modifier = Modifier
                .align(Alignment.Center)
                .padding(start = 80.dp),
        )
    }
}

private fun LazyListScopePolyfill() = Unit

private fun androidx.compose.foundation.lazy.LazyListScope.items(count: Int, block: @Composable (Int) -> Unit) {
    items(count = count, key = null) { i -> block(i) }
}

@Composable
private fun WheelItem(
    text: String,
    itemHeight: androidx.compose.ui.unit.Dp,
    isSelected: Boolean,
    distanceFromSelected: Int,
) {
    val alpha = when (distanceFromSelected) {
        0 -> 1f
        1 -> 0.55f
        2 -> 0.25f
        else -> 0.12f
    }
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .height(itemHeight),
        contentAlignment = Alignment.Center,
    ) {
        Text(
            text = text,
            color = MaterialTheme.colorScheme.onBackground,
            fontSize = if (isSelected) 34.sp else 30.sp,
            fontWeight = if (isSelected) FontWeight.SemiBold else FontWeight.Normal,
            textAlign = TextAlign.Center,
            modifier = Modifier.alpha(alpha),
        )
    }
}

