package com.dthanh.timeryt

import android.Manifest
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import android.content.pm.PackageManager
import android.os.Build
import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.result.contract.ActivityResultContracts
import androidx.compose.runtime.collectAsState
import androidx.compose.runtime.getValue
import androidx.core.content.ContextCompat
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import com.dthanh.timeryt.ui.TimerScreen
import com.dthanh.timeryt.ui.TimerYTTheme

class MainActivity : ComponentActivity() {

    private val requestNotifPerm = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { /* ignore result; service still works without it */ }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            val granted = ContextCompat.checkSelfPermission(
                this, Manifest.permission.POST_NOTIFICATIONS
            ) == PackageManager.PERMISSION_GRANTED
            if (!granted) requestNotifPerm.launch(Manifest.permission.POST_NOTIFICATIONS)
        }

        setContent {
            TimerYTTheme {
                val running by TimerState.running.collectAsStateWithLifecycle()
                val remaining by TimerState.remainingSeconds.collectAsStateWithLifecycle()
                TimerScreen(
                    running = running,
                    remainingSeconds = remaining,
                    onStart = { h, m, s ->
                        val total = h * 3600L + m * 60L + s
                        TimerService.start(this, total)
                    },
                    onCancel = { TimerService.stop(this) },
                )
            }
        }
    }
}

