package com.dthanh.timeryt

import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow

/**
 * Process-global flows that the UI observes. The TimerService writes to these.
 * A real production app would use a repository + LiveData/Flow scoped to the
 * service; for a single-screen timer the global object is fine.
 */
object TimerState {
    private val _running = MutableStateFlow(false)
    val running: StateFlow<Boolean> = _running.asStateFlow()

    private val _remainingSeconds = MutableStateFlow(0L)
    val remainingSeconds: StateFlow<Long> = _remainingSeconds.asStateFlow()

    internal fun update(running: Boolean, remaining: Long) {
        _running.value = running
        _remainingSeconds.value = remaining
    }
}

