package com.dthanh.timeryt

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.app.Service
import android.content.Context
import android.content.Intent
import android.media.AudioManager
import android.os.Build
import android.os.CountDownTimer
import android.os.IBinder
import android.os.SystemClock
import android.view.KeyEvent
import androidx.core.app.NotificationCompat

class TimerService : Service() {

    private var countdown: CountDownTimer? = null
    private var totalMs: Long = 0
    private var endAtElapsed: Long = 0

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onCreate() {
        super.onCreate()
        createChannel()
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        when (intent?.action) {
            ACTION_START -> {
                val seconds = intent.getLongExtra(EXTRA_SECONDS, 0L)
                if (seconds > 0) startTimer(seconds)
            }
            ACTION_STOP -> {
                stopTimer(finished = false)
            }
        }
        return START_NOT_STICKY
    }

    private fun startTimer(seconds: Long) {
        countdown?.cancel()
        totalMs = seconds * 1000L
        endAtElapsed = SystemClock.elapsedRealtime() + totalMs

        startForeground(NOTIF_ID, buildNotification(seconds))
        TimerState.update(running = true, remaining = seconds)

        countdown = object : CountDownTimer(totalMs, 250L) {
            override fun onTick(msRemaining: Long) {
                val secLeft = (msRemaining + 999L) / 1000L
                TimerState.update(running = true, remaining = secLeft)
                updateNotification(secLeft)
            }
            override fun onFinish() {
                pauseMediaPlayback()
                TimerState.update(running = false, remaining = 0L)
                showFinishedNotification()
                stopForeground(STOP_FOREGROUND_REMOVE)
                stopSelf()
            }
        }.start()
    }

    private fun stopTimer(finished: Boolean) {
        countdown?.cancel()
        countdown = null
        if (finished) pauseMediaPlayback()
        TimerState.update(running = false, remaining = 0L)
        stopForeground(STOP_FOREGROUND_REMOVE)
        stopSelf()
    }

    /**
     * Dispatch a media KEYCODE_MEDIA_PAUSE. YouTube and every other media app
     * registered as the active media session will receive it and pause.
     * Works whether YouTube is in the foreground, in the background or in PIP.
     */
    private fun pauseMediaPlayback() {
        val am = getSystemService(Context.AUDIO_SERVICE) as AudioManager
        val now = SystemClock.uptimeMillis()
        am.dispatchMediaKeyEvent(KeyEvent(now, now, KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_MEDIA_PAUSE, 0))
        am.dispatchMediaKeyEvent(KeyEvent(now, now, KeyEvent.ACTION_UP, KeyEvent.KEYCODE_MEDIA_PAUSE, 0))
    }

    private fun buildNotification(secondsLeft: Long): Notification {
        val openIntent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_SINGLE_TOP
        }
        val openPi = PendingIntent.getActivity(
            this, 0, openIntent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE,
        )
        val cancelPi = PendingIntent.getService(
            this, 1,
            Intent(this, TimerService::class.java).setAction(ACTION_STOP),
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE,
        )
        return NotificationCompat.Builder(this, CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_lock_idle_alarm)
            .setContentTitle(getString(R.string.notif_title))
            .setContentText(formatTime(secondsLeft))
            .setOngoing(true)
            .setOnlyAlertOnce(true)
            .setContentIntent(openPi)
            .addAction(0, "Cancel", cancelPi)
            .setCategory(NotificationCompat.CATEGORY_PROGRESS)
            .setUsesChronometer(false)
            .build()
    }

    private fun updateNotification(secondsLeft: Long) {
        val nm = getSystemService(NotificationManager::class.java)
        nm.notify(NOTIF_ID, buildNotification(secondsLeft))
    }

    private fun showFinishedNotification() {
        val nm = getSystemService(NotificationManager::class.java)
        val n = NotificationCompat.Builder(this, CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_lock_idle_alarm)
            .setContentTitle(getString(R.string.notif_title))
            .setContentText(getString(R.string.notif_finished))
            .setAutoCancel(true)
            .build()
        nm.notify(NOTIF_ID + 1, n)
    }

    private fun createChannel() {
        val nm = getSystemService(NotificationManager::class.java)
        val ch = NotificationChannel(
            CHANNEL_ID,
            getString(R.string.notif_channel_name),
            NotificationManager.IMPORTANCE_LOW,
        ).apply {
            setShowBadge(false)
            enableVibration(false)
        }
        nm.createNotificationChannel(ch)
    }

    private fun formatTime(seconds: Long): String {
        val h = seconds / 3600
        val m = (seconds % 3600) / 60
        val s = seconds % 60
        return if (h > 0) "%d:%02d:%02d".format(h, m, s) else "%d:%02d".format(m, s)
    }

    companion object {
        private const val CHANNEL_ID = "timer_yt_channel"
        private const val NOTIF_ID = 1001
        private const val ACTION_START = "com.dthanh.timeryt.START"
        private const val ACTION_STOP = "com.dthanh.timeryt.STOP"
        private const val EXTRA_SECONDS = "extra_seconds"

        fun start(ctx: Context, seconds: Long) {
            val i = Intent(ctx, TimerService::class.java)
                .setAction(ACTION_START)
                .putExtra(EXTRA_SECONDS, seconds)
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                ctx.startForegroundService(i)
            } else {
                ctx.startService(i)
            }
        }

        fun stop(ctx: Context) {
            val i = Intent(ctx, TimerService::class.java).setAction(ACTION_STOP)
            ctx.startService(i)
        }
    }
}

