/**
 * Linearly ramp STREAM_MUSIC from its captured level down to 0 across the
 * final [fadeWindowMs] milliseconds. We capture the starting level the
 * first tick we enter the window so the user's pre-fade level is what we
 * restore later.
 */
private fun applyFade(msRemaining: Long) {
    if (msRemaining > fadeWindowMs) return
    val am = getSystemService(Context.AUDIO_SERVICE) as AudioManager
    if (fadeStartVolume < 0) {
        fadeStartVolume = am.getStreamVolume(AudioManager.STREAM_MUSIC)
        if (fadeStartVolume <= 0) return  // already silent — nothing to fade
    }
    val fraction = (msRemaining.toFloat() / fadeWindowMs.toFloat()).coerceIn(0f, 1f)
    val target = (fadeStartVolume * fraction).toInt().coerceIn(0, fadeStartVolume)
    // FLAG 0 = no UI, no beep on each step
    am.setStreamVolume(AudioManager.STREAM_MUSIC, target, 0)
}

private fun restoreVolume() {
    if (fadeStartVolume < 0) return
    val am = getSystemService(Context.AUDIO_SERVICE) as AudioManager
    am.setStreamVolume(AudioManager.STREAM_MUSIC, fadeStartVolume, 0)
    fadeStartVolume = -1
}

